export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private results: NotificationResult[] = [];
  private preferencesService?: PreferencesService;
  private historyService?: NotificationHistoryService;
  /** Per-user promise chains to ensure notification ordering within each user. */
  private userQueues: Map<string, Promise<void>> = new Map();

