/**
 * Enqueue a notification for delivery, ensuring per-user ordering.
 * Notifications for the same user are serialized via a promise chain,
 * preventing out-of-order delivery (e.g., "payment confirmed" before "order placed").
 */
private async sendNotification(params: {
  type: NotificationPayload['type'];
  channel: NotificationChannel;
  recipient: string;
  userId?: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
}): Promise<NotificationResult | undefined> {
  const queueKey = params.userId ?? params.recipient;
  const previous = this.userQueues.get(queueKey) ?? Promise.resolve();

  let result: NotificationResult | undefined;
  const current = previous.then(async () => {
    result = await this.processSendNotification(params);
  });

  // Store the chain but swallow errors so subsequent notifications still run
  this.userQueues.set(queueKey, current.catch(() => {}));

  await current;
  return result;
}

/**
